import express from "express";
import vm from "node:vm";
import process from "node:process";

const app = express();
app.use(express.json({ limit: "1mb" }));

const PORT = process.env.PORT || 3000;
const OPENAI_API_KEY = process.env.OPENAI_API_KEY;
const OPENAI_MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

if (!OPENAI_API_KEY) {
  console.error("Missing OPENAI_API_KEY");
  process.exit(1);
}

function buildPrompt(description, input) {
  return [
    "You are a JavaScript code generator for a no-code automation platform.",
    "Return only runnable JavaScript for a pure function named run.",
    "The function signature must be: async function run(input) {}",
    "Do not access network, filesystem, child processes, environment variables, timers, or dynamic imports.",
    "Do not use require, import, eval, Function constructor, WebAssembly, process, globalThis, or modules.",
    "The function must return JSON-serializable output.",
    "No markdown. No explanation. Output code only.",
    "",
    "User request:",
    description,
    "",
    "Input JSON:",
    JSON.stringify(input ?? {})
  ].join("\n");
}

async function generateCode(description, input) {
  const response = await fetch("https://api.openai.com/v1/responses", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${OPENAI_API_KEY}`
    },
    body: JSON.stringify({
      model: OPENAI_MODEL,
      input: buildPrompt(description, input)
    })
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Model API error: ${response.status} ${text}`);
  }

  const data = await response.json();
  const text =
    data.output_text ||
    data.output?.flatMap(x => x.content || []).map(x => x.text || "").join("") ||
    "";

  if (!text.trim()) {
    throw new Error("Empty code returned from model");
  }

  return text.trim();
}

function validateCode(code) {
  const bannedPatterns = [
    /\brequire\s*\(/,
    /\bimport\s*\(/,
    /\bimport\s.+from\s.+/,
    /\bexport\b/,
    /\beval\s*\(/,
    /\bFunction\s*\(/,
    /\bAsyncFunction\s*\(/,
    /\bGeneratorFunction\s*\(/,
    /\bWebAssembly\b/,
    /\bfetch\s*\(/,
    /\bXMLHttpRequest\b/,
    /\bprocess\b/,
    /\bglobalThis\b/,
    /\bglobal\b/,
    /\bmodule\b/,
    /\bexports\b/,
    /\bsetTimeout\b/,
    /\bsetInterval\b/,
    /\bqueueMicrotask\b/,
    /\bfs\b/,
    /\bchild_process\b/,
    /\bworker_threads\b/,
    /\bhttp\b/,
    /\bhttps\b/,
    /\bnet\b/,
    /\bdgram\b/,
    /\bvm\b/
  ];

  for (const pattern of bannedPatterns) {
    if (pattern.test(code)) {
      throw new Error(`Generated code contains disallowed pattern: ${pattern}`);
    }
  }

  if (!/async\s+function\s+run\s*\(\s*input\s*\)/.test(code) && !/const\s+run\s*=\s*async\s*\(\s*input\s*\)\s*=>/.test(code)) {
    throw new Error("Generated code must define async function run(input)");
  }
}

async function executeCode(code, input) {
  validateCode(code);

  const sandbox = Object.create(null);
  sandbox.JSON = JSON;
  sandbox.Math = Math;
  sandbox.Number = Number;
  sandbox.String = String;
  sandbox.Boolean = Boolean;
  sandbox.Array = Array;
  sandbox.Object = Object;
  sandbox.Date = Date;
  sandbox.RegExp = RegExp;
  sandbox.URL = URL;
  sandbox.URLSearchParams = URLSearchParams;
  sandbox.console = {
    log: () => {},
    error: () => {},
    warn: () => {},
    info: () => {}
  };

  const context = vm.createContext(sandbox, {
    name: "automation-sandbox",
    codeGeneration: { strings: false, wasm: false }
  });

  const wrapped = `
"use strict";
${code}
if (typeof run !== "function") {
  throw new Error("run function not defined");
}
run;
`;

  const script = new vm.Script(wrapped, { timeout: 1000 });
  const fn = script.runInContext(context, { timeout: 1000 });

  const result = await Promise.race([
    fn(input),
    new Promise((_, reject) => setTimeout(() => reject(new Error("Execution timeout")), 1500))
  ]);

  return JSON.parse(JSON.stringify(result));
}

app.post("/generate-and-run", async (req, res) => {
  try {
    const { description, input } = req.body || {};

    if (!description || typeof description !== "string") {
      return res.status(400).json({ error: "description must be a non-empty string" });
    }

    const code = await generateCode(description, input ?? {});
    const output = await executeCode(code, input ?? {});

    res.json({ code, output });
  } catch (error) {
    res.status(500).json({
      error: error instanceof Error ? error.message : "Unknown error"
    });
  }
});

app.get("/health", (_req, res) => {
  res.json({ ok: true });
});

app.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});